#!/bin/bash
# train/scripts/download_datasets.sh — Kick off all dataset downloads.
#
# Defaults to train/data/ as the data root (symlink or real directory).
# Run train/scripts/setup_data_dir.sh first to configure that directory.
#
# Usage:
#   source train/.venv/bin/activate
#   bash train/scripts/download_datasets.sh
#
# Override data root:
#   bash train/scripts/download_datasets.sh --data-root /Volumes/IrisData
#
# Required: train/data/raw/laion_filtered.parquet generated by prepare_laion.py

set -e

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
TRAIN_DIR="$(dirname "$SCRIPT_DIR")"
DATA_ROOT="${DATA_ROOT:-$TRAIN_DIR/data}"
LAION_PARQUET="$DATA_ROOT/raw/laion_filtered.parquet"

while [[ $# -gt 0 ]]; do
    case $1 in
        --data-root) DATA_ROOT="$2"; shift 2 ;;
        --laion)     LAION_PARQUET="$2"; shift 2 ;;
        # Legacy flag kept for backwards compatibility
        --ssd)       DATA_ROOT="$2"; shift 2 ;;
        *) echo "Unknown arg: $1"; exit 1 ;;
    esac
done

# ── Verify data root is set up ────────────────────────────────────────────────
if [ ! -d "$DATA_ROOT" ]; then
    echo "Error: data root not found: $DATA_ROOT"
    echo "Run: bash train/scripts/setup_data_dir.sh"
    exit 1
fi

# ── Verify filtered LAION parquet exists ──────────────────────────────────────
if [ ! -f "$LAION_PARQUET" ]; then
    echo "Error: LAION parquet not found: $LAION_PARQUET"
    echo "Run: python train/scripts/prepare_laion.py \\"
    echo "       --output $LAION_PARQUET"
    exit 1
fi

# ── Resolve actual target (follow symlink for display) ───────────────────────
RESOLVED_ROOT="$(python3 -c "import os; print(os.path.realpath('$DATA_ROOT'))" 2>/dev/null || echo "$DATA_ROOT")"
IS_SYMLINK=""
if [ -L "$DATA_ROOT" ]; then
    IS_SYMLINK=" -> $RESOLVED_ROOT"
fi

echo "Data root: $DATA_ROOT$IS_SYMLINK"
echo ""

# ── Ensure raw subdirs exist ──────────────────────────────────────────────────
mkdir -p \
    "$DATA_ROOT/raw/laion" \
    "$DATA_ROOT/raw/journeydb" \
    "$DATA_ROOT/raw/coyo" \
    "$DATA_ROOT/raw/wikiart" \
    "$DATA_ROOT/shards" \
    "$DATA_ROOT/precomputed/qwen3" \
    "$DATA_ROOT/precomputed/vae" \
    "$DATA_ROOT/precomputed/siglip" \
    "$DATA_ROOT/checkpoints" \
    "$DATA_ROOT/weights" \
    "$DATA_ROOT/logs"

mkdir -p "$TRAIN_DIR/logs"

echo ""
echo "========================================================================"
echo "  Download plan — run each block in a separate terminal"
echo "========================================================================"

# ── WikiArt (tiny, run now) ───────────────────────────────────────────────────
echo ""
echo "── WikiArt (1.7 GB, fast) ──────────────────────────────────────────────"
echo "Run:"
echo "  hf download Artificio/WikiArt \\"
echo "    --repo-type dataset \\"
echo "    --local-dir $DATA_ROOT/raw/wikiart"
echo "  # Prepend style label to captions: 'An impressionist painting showing {caption}'"

# ── Warmstart weights (5.3 GB) ────────────────────────────────────────────────
echo ""
echo "── IP-Adapter warmstart weights (5.3 GB) ──────────────────────────────"
echo "Run:"
echo "  hf download InstantX/FLUX.1-dev-IP-Adapter \\"
echo "    --local-dir $DATA_ROOT/weights/flux_dev_ipadapter"
echo "  # Only image_proj.* keys transfer to Klein 4B (Perceiver Resampler warmstart)"

# ── Terminal 1: LAION-Aesthetics (~150 GB) ────────────────────────────────────
echo ""
echo "── TERMINAL 1: LAION-Aesthetics-v2 (~150 GB) ──────────────────────────"
echo "Run under caffeinate:"
cat <<LAION
  # Detect performance cores (M1 Max = 8; never hardcode)
  PERF_CORES=\$(sysctl -n hw.perflevel0.logicalcpu 2>/dev/null || nproc)
  IO_THREADS=\$((PERF_CORES * 2))

  caffeinate -i -d \\
  img2dataset \\
    --url_list $LAION_PARQUET \\
    --input_format parquet \\
    --url_col url \\
    --caption_col caption \\
    --output_format webdataset \\
    --output_folder $DATA_ROOT/raw/laion \\
    --image_size 512 \\
    --resize_only_if_bigger True \\
    --resize_mode keep_ratio_largest \\
    --encode_format jpg \\
    --encode_quality 85 \\
    --processes_count \$PERF_CORES \\
    --thread_count \$IO_THREADS \\
    2>&1 | tee $DATA_ROOT/logs/laion_download.log
LAION

# ── Terminal 2: JourneyDB (~80 GB) ───────────────────────────────────────────
echo ""
echo "── TERMINAL 2: JourneyDB (~80 GB, non-commercial research) ────────────"
echo "Note: accept terms at https://huggingface.co/datasets/JourneyDB/JourneyDB first"
cat <<JDB
  caffeinate -i -d \\
  python3 -c "
from huggingface_hub import snapshot_download
snapshot_download(
    'JourneyDB/JourneyDB',
    repo_type='dataset',
    local_dir='$DATA_ROOT/raw/journeydb',
    allow_patterns=['data/train/**'],
)" \\
    2>&1 | tee $DATA_ROOT/logs/journeydb_download.log
JDB

# ── Terminal 3: COYO filtered (~25 GB) ───────────────────────────────────────
echo ""
echo "── TERMINAL 3: COYO filtered (~25 GB) ─────────────────────────────────"
echo "Note: prepare COYO parquet first — see scripts/prepare_coyo.py"
cat <<COYO
  PERF_CORES=\$(sysctl -n hw.perflevel0.logicalcpu 2>/dev/null || nproc)
  IO_THREADS=\$((PERF_CORES * 2))

  caffeinate -i -d \\
  img2dataset \\
    --url_list $DATA_ROOT/raw/coyo_filtered.parquet \\
    --input_format parquet \\
    --url_col url \\
    --caption_col caption \\
    --output_format webdataset \\
    --output_folder $DATA_ROOT/raw/coyo \\
    --image_size 512 \\
    --resize_only_if_bigger True \\
    --resize_mode keep_ratio_largest \\
    --encode_format jpg \\
    --encode_quality 85 \\
    --processes_count \$PERF_CORES \\
    --thread_count \$IO_THREADS \\
    2>&1 | tee $DATA_ROOT/logs/coyo_download.log
COYO

echo ""
echo "========================================================================"
echo "  After all downloads complete, run:"
echo "    caffeinate -i -d bash train/scripts/run_preprocessing.sh"
echo "========================================================================"

echo ""
echo "── TB4 health check (run in background during downloads) ────────────────"
cat <<HEALTH
  while true; do
    if [ ! -d "$DATA_ROOT" ]; then
      echo "\$(date): data root unmounted: $DATA_ROOT" | tee -a $DATA_ROOT/logs/health.log
    fi
    sleep 300
  done &
HEALTH
